import { Component } from '@angular/core';
import { AuthService } from '../_services/auth.service';

@Component({
  selector: 'register',
  templateUrl: './register.component.html',
  styleUrls: ['./register.component.css']
})
export class RegisterComponent {

model: any = {};

constructor(private authService: AuthService) {}

register(){
  this.authService.register(this.model).subscribe(()=>{
    console.log("kullanıcı oluşturuldu");
  },error =>{
    console.log(error);
  });
}

}
<div class="container" style="margin-top: 150px;">
<div class="row">
  <div class="col-6">
    <form #form="ngForm" (ngSubmit)="register()">
      <h2>Register</h2>
      <hr>
      <div class="form-group">
        <input required minlength="5" #name="ngModel" maxlength="25" type="text" name="name" [(ngModel)]="model.name" class="form-control" placeholder="Name">
      </div>
      <div class="alert alert-danger" *ngIf="name.invalid  && name.touched">
        <p *ngIf="name.errors?.['required']">Name is Required</p>
        <p *ngIf="name.errors?.['minlength']">Min. 5 charactes</p>
        <!-- <p *ngIf="name.errors.minlength">Min. 5 charactes</p> -->
      </div>
      <div class="form-group">
        <input required type="text" name="username" [(ngModel)]="model.username" class="form-control" placeholder="UserName">
      </div>
      <div class="form-group">
        <input required email type="email" name="email" [(ngModel)]="model.email" class="form-control" placeholder="Email">
      </div>
      <div class="form-group">
        <input required minlength="6" maxlength="15" type="password" name="password" [(ngModel)]="model.password" class="form-control" placeholder="Password">
      </div>
      <button [disabled]="form.invalid" class="btn btn-primary btn-block" type="submit">Submit</button>
      <!-- #form="ngForm" bir üs satırdaki form -->
    </form>
  </div>
</div>
</div>
